SELECT COUNT(station_id) AS total_stations_with_restaurant
FROM service_stations
WHERE has_restaurant = 1;

SELECT name
FROM service_stations
WHERE has_restaurant = 1 AND has_car_wash = 1;

SELECT DISTINCT station_id, name
FROM service_stations
WHERE county = 'Dublin';

SELECT AVG(price) AS average_price
FROM fuel_prices
WHERE fuel_type_id = (SELECT fuel_type_id FROM fuel_types WHERE fuel_type_name = 'Diesel');
